package com.cho2hand.marketplace.service.impl.comment;import com.cho2hand.marketplace.dto.comment.*;import com.cho2hand.marketplace.entity.comment.Comment;import com.cho2hand.marketplace.exception.ListingNotFoundException;import com.cho2hand.marketplace.repository.comment.CommentRepository;import com.cho2hand.marketplace.repository.listing.ListingRepository;import com.cho2hand.marketplace.service.comment.CommentService;import java.util.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service @Transactional public class CommentServiceImpl implements CommentService{private final CommentRepository comments;private final ListingRepository listings;public CommentServiceImpl(CommentRepository c,ListingRepository l){comments=c;listings=l;}public CommentResponse create(Long user,Long listing,CreateCommentRequest r){listings.findById(listing).filter(v->v.getArchivedAt()==null).orElseThrow(()->new ListingNotFoundException(listing));var c=new Comment();c.setListingId(listing);c.setAuthorUserId(user);c.setBody(r.body().trim());return response(comments.save(c));}@Transactional(readOnly=true)public List<CommentResponse> list(Long listing){return comments.findByListingIdAndStatusOrderByCreatedAtAsc(listing,"VISIBLE").stream().map(this::response).toList();}private CommentResponse response(Comment c){return new CommentResponse(c.getId(),c.getAuthorUserId(),c.getBody(),c.getCreatedAt());}}
